100:     /**
101:      * Set up a fetch request for any node that we have assigned partitions for which doesn't already have
102:      * an in-flight fetch or pending fetch data.
103:      * @return number of fetches sent
104:      */
105:     public synchronized int sendFetches() {
106:         final Map<Node, FetchSessionHandler.FetchRequestData> fetchRequests = prepareFetchRequests();
107:         sendFetchesInternal(
108:                 fetchRequests,
109:                 (fetchTarget, data, clientResponse) -> {
110:                     synchronized (Fetcher.this) {
111:                         handleFetchSuccess(fetchTarget, data, clientResponse);
112:                     }
113:                 },
114:                 (fetchTarget, data, error) -> {
115:                     synchronized (Fetcher.this) {
116:                         handleFetchFailure(fetchTarget, data, error);
117:                     }
118:                 });
119:         return fetchRequests.size();
120:     }
