62:  * {@code AbstractFetch} represents the basic state and logic for record fetching processing.
63:  */
64: public abstract class AbstractFetch implements Closeable {
65: 
66:     private final Logger log;
67:     // Calling LoggerFactory.getLogger() is pretty expensive with log4j2. See KAFKA-18046 for details.
68:     // We cache the logger used by CompletedFetch because it is created on every fetch responses.
69:     private final Logger completedFetchLog;
