143:     /**
144:      * Implements the core logic for a successful fetch response.
145:      *
146:      * @param fetchTarget {@link Node} from which the fetch data was requested
147:      * @param data {@link FetchSessionHandler.FetchRequestData} that represents the session data
148:      * @param resp {@link ClientResponse} from which the {@link FetchResponse} will be retrieved
149:      */
150:     protected void handleFetchSuccess(final Node fetchTarget,
151:                                       final FetchSessionHandler.FetchRequestData data,
152:                                       final ClientResponse resp) {
153:         try {
154:             final FetchResponse response = (FetchResponse) resp.responseBody();
155:             final FetchSessionHandler handler = sessionHandler(fetchTarget.id());
156: 
157:             if (handler == null) {
158:                 log.error("Unable to find FetchSessionHandler for node {}. Ignoring fetch response.",
159:                         fetchTarget.id());
160:                 return;
161:             }
162: 
163:             final short requestVersion = resp.requestHeader().apiVersion();
164: 
165:             if (!handler.handleResponse(response, requestVersion)) {
166:                 if (response.error() == Errors.FETCH_SESSION_TOPIC_ID_ERROR) {
167:                     metadata.requestUpdate(false);
168:                 }
169: 
170:                 return;
171:             }
172: 
173:             final Map<TopicPartition, FetchResponseData.PartitionData> responseData = response.responseData(handler.sessionTopicNames(), requestVersion);
174:             final Set<TopicPartition> partitions = new HashSet<>(responseData.keySet());
175:             final FetchMetricsAggregator metricAggregator = new FetchMetricsAggregator(metricsManager, partitions);
176: 
177:             Map<TopicPartition, Metadata.LeaderIdAndEpoch> partitionsWithUpdatedLeaderInfo = new HashMap<>();
178:             for (Map.Entry<TopicPartition, FetchResponseData.PartitionData> entry : responseData.entrySet()) {
179:                 TopicPartition partition = entry.getKey();
180:                 FetchRequest.PartitionData requestData = data.sessionPartitions().get(partition);
181: 
182:                 if (requestData == null) {
183:                     String message;
184: 
185:                     if (data.metadata().isFull()) {
186:                         message = MessageFormatter.arrayFormat(
187:                                 "Response for missing full request partition: partition={}; metadata={}",
188:                                 new Object[]{partition, data.metadata()}).getMessage();
189:                     } else {
190:                         message = MessageFormatter.arrayFormat(
191:                                 "Response for missing session request partition: partition={}; metadata={}; toSend={}; toForget={}; toReplace={}",
192:                                 new Object[]{partition, data.metadata(), data.toSend(), data.toForget(), data.toReplace()}).getMessage();
193:                     }
194: 
195:                     // Received fetch response for missing session partition
196:                     throw new IllegalStateException(message);
197:                 }
198: 
199:                 long fetchOffset = requestData.fetchOffset;
200:                 FetchResponseData.PartitionData partitionData = entry.getValue();
201: 
202:                 log.debug("Fetch {} at offset {} for partition {} returned fetch data {}",
203:                         fetchConfig.isolationLevel, fetchOffset, partition, partitionData);
204: 
205:                 Errors partitionError = Errors.forCode(partitionData.errorCode());
206:                 if (partitionError == Errors.NOT_LEADER_OR_FOLLOWER || partitionError == Errors.FENCED_LEADER_EPOCH) {
207:                     log.debug("For {}, received error {}, with leaderIdAndEpoch {}", partition, partitionError, partitionData.currentLeader());
208:                     if (partitionData.currentLeader().leaderId() != -1 && partitionData.currentLeader().leaderEpoch() != -1) {
209:                         partitionsWithUpdatedLeaderInfo.put(partition, new Metadata.LeaderIdAndEpoch(
210:                             Optional.of(partitionData.currentLeader().leaderId()), Optional.of(partitionData.currentLeader().leaderEpoch())));
211:                     }
212:                 }
213: 
214:                 CompletedFetch completedFetch = new CompletedFetch(
215:                         completedFetchLog,
216:                         subscriptions,
217:                         decompressionBufferSupplier,
218:                         partition,
219:                         partitionData,
220:                         metricAggregator,
221:                         fetchOffset);
222:                 fetchBuffer.add(completedFetch);
223:             }
224: 
225:             if (!partitionsWithUpdatedLeaderInfo.isEmpty()) {
226:                 List<Node> leaderNodes = new ArrayList<>();
227: 
228:                 for (FetchResponseData.NodeEndpoint e : response.data().nodeEndpoints()) {
229:                     Node node = new Node(e.nodeId(), e.host(), e.port(), e.rack());
230: 
231:                     if (!node.equals(Node.noNode()))
232:                         leaderNodes.add(node);
233:                 }
234: 
235:                 Set<TopicPartition> updatedPartitions = metadata.updatePartitionLeadership(partitionsWithUpdatedLeaderInfo, leaderNodes);
236:                 updatedPartitions.forEach(
237:                     tp -> {
238:                         log.debug("For {}, as the leader was updated, position will be validated.", tp);
239:                         subscriptions.maybeValidatePositionForCurrentLeader(apiVersions, tp, metadata.currentLeader(tp));
240:                     }
241:                 );
242:             }
243: 
244:             metricsManager.recordLatency(resp.destination(), resp.requestLatencyMs());
245:         } finally {
246:             removePendingFetchRequest(fetchTarget, data.metadata().sessionId());
247:         }
248:     }
