481:     /**
482:      * This method converts {@link FetchSessionHandler.Builder} instances to
483:      * {@link FetchSessionHandler.FetchRequestData} instances. It intentionally forgoes use of the Java Collections
484:      * Streams API to reduce overhead in the critical network path.
485:      */
486:     private Map<Node, FetchSessionHandler.FetchRequestData> convert(Map<Node, FetchSessionHandler.Builder> fetchable) {
487:         Map<Node, FetchSessionHandler.FetchRequestData> map = new HashMap<>(fetchable.size());
488: 
489:         for (Map.Entry<Node, FetchSessionHandler.Builder> entry : fetchable.entrySet())
490:             map.put(entry.getKey(), entry.getValue().build());
491: 
492:         return map;
