495:     /**
496:      * Simple utility method that returns a {@link SubscriptionState.FetchPosition position} for the partition. If
497:      * no position exists, an {@link IllegalStateException} is thrown.
498:      */
499:     private SubscriptionState.FetchPosition positionForPartition(TopicPartition partition) {
500:         SubscriptionState.FetchPosition position = subscriptions.position(partition);
501: 
502:         if (position == null)
503:             throw new IllegalStateException("Missing position for fetchable partition " + partition);
504: 
505:         return position;
506:     }
