508:     /**
509:      * Retrieves the node from which to fetch the partition data. If the given
510:      * {@link SubscriptionState.FetchPosition position} does not have a current
511:      * {@link Metadata.LeaderAndEpoch#leader leader} defined the method will return {@link Optional#empty()}.
512:      *
513:      * @return Three options: 1) {@link Optional#empty()} if the position's leader is empty, 2) the
514:      * {@link #selectReadReplica(TopicPartition, Node, long) read replica, if defined}, or 3) the position's
515:      * {@link Metadata.LeaderAndEpoch#leader leader}
516:      */
517:     private Optional<Node> maybeNodeForPosition(TopicPartition partition,
518:                                                 SubscriptionState.FetchPosition position,
519:                                                 long currentTimeMs) {
520:         Optional<Node> leaderOpt = position.currentLeader.leader;
521: 
522:         if (leaderOpt.isEmpty()) {
523:             log.debug("Requesting metadata update for partition {} since the position {} is missing the current leader node", partition, position);
524:             metadata.requestUpdate(false);
525:             return Optional.empty();
526:         }
527: 
528:         // Use the preferred read replica if set, otherwise the partition's leader
529:         Node node = selectReadReplica(partition, leaderOpt.get(), currentTimeMs);
530:         return Optional.of(node);
531:     }
