43: /**
44:  * {@code FetchCollector} operates at the {@link RecordBatch} level, as that is what is stored in the
45:  * {@link FetchBuffer}. Each {@link org.apache.kafka.common.record.Record} in the {@link RecordBatch} is converted
46:  * to a {@link ConsumerRecord} and added to the returned {@link Fetch}.
47:  *
48:  * @param <K> Record key type
49:  * @param <V> Record value type
50:  */
51: public class FetchCollector<K, V> {
52: 
53:     private final Logger log;
54:     private final ConsumerMetadata metadata;
55:     private final SubscriptionState subscriptions;
56:     private final FetchConfig fetchConfig;
