63:                           final SubscriptionState subscriptions,
64:                           final FetchConfig fetchConfig,
65:                           final Deserializers<K, V> deserializers,
66:                           final FetchMetricsManager metricsManager,
67:                           final Time time) {
68:         this.log = logContext.logger(FetchCollector.class);
69:         this.metadata = metadata;
70:         this.subscriptions = subscriptions;
71:         this.fetchConfig = fetchConfig;
72:         this.deserializers = deserializers;
73:         this.metricsManager = metricsManager;
74:         this.time = time;
75:     }
