178: 
179:                 if (nextInLineFetch.nextFetchOffset() > position.offset) {
180:                     SubscriptionState.FetchPosition nextPosition = new SubscriptionState.FetchPosition(
181:                             nextInLineFetch.nextFetchOffset(),
182:                             nextInLineFetch.lastEpoch(),
183:                             position.currentLeader);
184:                     log.trace("Updating fetch position from {} to {} for partition {} and returning {} records from `poll()`",
