164:     private void maybeEnsureValid(FetchConfig fetchConfig, Record record) {
165:         if (fetchConfig.checkCrcs) {
166:             try {
167:                 record.ensureValid();
168:             } catch (CorruptRecordException e) {
169:                 throw new KafkaException("Record for partition " + partition + " at offset " + record.offset()
170:                         + " is invalid, cause: " + e.getMessage());
