187:                 if (!batches.hasNext()) {
188:                     // Message format v2 preserves the last offset in a batch even if the last record is removed
189:                     // through compaction. By using the next offset computed from the last offset in the batch,
190:                     // we ensure that the offset of the next fetch will point to the next batch, which avoids
191:                     // unnecessary re-fetching of the same batch (in the worst case, the consumer could get stuck
192:                     // fetching the same batch repeatedly).
193:                     if (currentBatch != null)
194:                         nextFetchOffset = currentBatch.nextOffset();
195:                     drain();
196:                     return null;
197:                 }
198: 
199:                 currentBatch = batches.next();
200:                 lastEpoch = maybeLeaderEpoch(currentBatch.partitionLeaderEpoch());
