376:     private boolean containsAbortMarker(RecordBatch batch) {
377:         if (!batch.isControlBatch())
378:             return false;
379: 
380:         Iterator<Record> batchIterator = batch.iterator();
381:         if (!batchIterator.hasNext())
382:             return false;
383: 
384:         Record firstRecord = batchIterator.next();
385:         return ControlRecordType.ABORT == ControlRecordType.parse(firstRecord.key());
386:     }
