33: public class Fetch<K, V> {
34:     private final Map<TopicPartition, List<ConsumerRecord<K, V>>> records;
35:     private final Map<TopicPartition, OffsetAndMetadata> nextOffsetAndMetadata;
36:     private boolean positionAdvanced;
37:     private int numRecords;
38: 
39:     public static <K, V> Fetch<K, V> empty() {
40:         return new Fetch<>(new HashMap<>(), false, 0, new HashMap<>());
41:     }
42: 
43:     public static <K, V> Fetch<K, V> forPartition(
44:             TopicPartition partition,
45:             List<ConsumerRecord<K, V>> records,
46:             boolean positionAdvanced,
47:             OffsetAndMetadata nextOffsetAndMetadata
48:     ) {
49:         Map<TopicPartition, List<ConsumerRecord<K, V>>> recordsMap = records.isEmpty()
50:                 ? new HashMap<>()
51:                 : mkMap(mkEntry(partition, records));
52:         Map<TopicPartition, OffsetAndMetadata> nextOffsetAndMetadataMap = mkMap(mkEntry(partition, nextOffsetAndMetadata));
53:         return new Fetch<>(recordsMap, positionAdvanced, records.size(), nextOffsetAndMetadataMap);
54:     }
55: 
56:     private Fetch(
57:             Map<TopicPartition, List<ConsumerRecord<K, V>>> records,
58:             boolean positionAdvanced,
59:             int numRecords,
60:             Map<TopicPartition, OffsetAndMetadata> nextOffsetAndMetadata
61:     ) {
62:         this.records = records;
63:         this.positionAdvanced = positionAdvanced;
64:         this.numRecords = numRecords;
65:         this.nextOffsetAndMetadata = nextOffsetAndMetadata;
66:     }
67: 
68:     /**
69:      * Add another {@link Fetch} to this one; all of its records will be added to this fetch's
70:      * {@link #records() records}, and if the other fetch
71:      * {@link #positionAdvanced() advanced the consume position for any topic partition},
72:      * this fetch will be marked as having advanced the consume position as well.
73:      * @param fetch the other fetch to add; may not be null
74:      */
75:     public void add(Fetch<K, V> fetch) {
76:         Objects.requireNonNull(fetch);
77:         addRecords(fetch.records);
78:         this.positionAdvanced |= fetch.positionAdvanced;
79:         this.nextOffsetAndMetadata.putAll(fetch.nextOffsetAndMetadata);
80:     }
81: 
82:     /**
83:      * @return all of the non-control messages for this fetch, grouped by partition
84:      */
85:     public Map<TopicPartition, List<ConsumerRecord<K, V>>> records() {
86:         return Collections.unmodifiableMap(records);
87:     }
88: 
89:     /**
90:      * @return whether the fetch caused the consumer's
91:      * {@link org.apache.kafka.clients.consumer.KafkaConsumer#position(TopicPartition) position} to advance for at
92:      * least one of the topic partitions in this fetch
93:      */
94:     public boolean positionAdvanced() {
95:         return positionAdvanced;
96:     }
97: 
98:     /**
99:      * @return the total number of non-control messages for this fetch, across all partitions
100:      */
101:     public int numRecords() {
102:         return numRecords;
103:     }
104: 
105:     /**
106:      * @return the next offsets and metadata that the consumer will consume (last epoch is included)
107:      */
108:     public Map<TopicPartition, OffsetAndMetadata> nextOffsets() {
109:         return Map.copyOf(nextOffsetAndMetadata);
110:     }
111: 
112:     /**
113:      * @return {@code true} if and only if this fetch did not return any user-visible (i.e., non-control) records, and
114:      * did not cause the consumer position to advance for any topic partitions
115:      */
116:     public boolean isEmpty() {
117:         return numRecords == 0 && !positionAdvanced;
118:     }
119: 
120:     private void addRecords(Map<TopicPartition, List<ConsumerRecord<K, V>>> records) {
121:         records.forEach((partition, partRecords) -> {
122:             this.numRecords += partRecords.size();
123:             List<ConsumerRecord<K, V>> currentRecords = this.records.get(partition);
124:             if (currentRecords == null) {
125:                 this.records.put(partition, partRecords);
126:             } else {
127:                 // this case shouldn't usually happen because we only send one fetch at a time per partition,
128:                 // but it might conceivably happen in some rare cases (such as partition leader changes).
129:                 // we have to copy to a new list because the old one may be immutable
130:                 List<ConsumerRecord<K, V>> newRecords = new ArrayList<>(currentRecords.size() + partRecords.size());
131:                 newRecords.addAll(currentRecords);
132:                 newRecords.addAll(partRecords);
133:                 this.records.put(partition, newRecords);
134:             }
135:         });
136:     }
137: }
