76:      * @see CreateFetchRequestsEvent
77:      * @return Future on which the caller can wait to ensure that the requests have been created
78:      */
79:     public CompletableFuture<Void> createFetchRequests() {
80:         CompletableFuture<Void> future = new CompletableFuture<>();
81: 
82:         if (pendingFetchRequestFuture != null) {
83:             // In this case, we have an outstanding fetch request, so chain the newly created future to be
84:             // completed when the "pending" future is completed.
85:             pendingFetchRequestFuture.whenComplete((value, exception) -> {
86:                 if (exception != null) {
87:                     future.completeExceptionally(exception);
88:                 } else {
89:                     future.complete(value);
90:                 }
91:             });
92:         } else {
93:             pendingFetchRequestFuture = future;
94:         }
95: 
96:         return future;
97:     }
