107:             this::handleFetchFailure
108:         );
109:     }
110: 
111:     /**
112:      * {@inheritDoc}
113:      */
114:     @Override
115:     public PollResult pollOnClose(long currentTimeMs) {
116:         // There needs to be a pending fetch request for pollInternal to create the requests.
117:         createFetchRequests();
118: 
119:         // TODO: move the logic to poll to handle signal close
120:         return pollInternal(
121:                 this::prepareCloseFetchSessionRequests,
122:                 this::handleCloseFetchSessionSuccess,
123:                 this::handleCloseFetchSessionFailure
124:         );
125:     }
126: 
127:     /**
128:      * Creates the {@link PollResult poll result} that contains a list of zero or more
129:      * {@link FetchRequest.Builder fetch requests}.
130:      *
131:      * @param fetchRequestPreparer {@link FetchRequestPreparer} to generate a {@link Map} of {@link Node nodes}
132:      *                             to their {@link FetchSessionHandler.FetchRequestData}
133:      * @param successHandler       {@link ResponseHandler Handler for successful responses}
134:      * @param errorHandler         {@link ResponseHandler Handler for failure responses}
135:      * @return {@link PollResult}
136:      */
137:     private PollResult pollInternal(FetchRequestPreparer fetchRequestPreparer,
138:                                     ResponseHandler<ClientResponse> successHandler,
139:                                     ResponseHandler<Throwable> errorHandler) {
140:         if (pendingFetchRequestFuture == null) {
141:             // If no explicit request for creating fetch requests was issued, just short-circuit.
142:             return PollResult.EMPTY;
143:         }
144: 
145:         try {
146:             Map<Node, FetchSessionHandler.FetchRequestData> fetchRequests = fetchRequestPreparer.prepare();
147: 
148:             List<UnsentRequest> requests = fetchRequests.entrySet().stream().map(entry -> {
149:                 final Node fetchTarget = entry.getKey();
150:                 final FetchSessionHandler.FetchRequestData data = entry.getValue();
151:                 final FetchRequest.Builder request = createFetchRequest(fetchTarget, data);
152:                 final BiConsumer<ClientResponse, Throwable> responseHandler = (clientResponse, error) -> {
153:                     if (error != null)
154:                         errorHandler.handle(fetchTarget, data, error);
155:                     else
156:                         successHandler.handle(fetchTarget, data, clientResponse);
157:                 };
158: 
159:                 return new UnsentRequest(request, Optional.of(fetchTarget)).whenComplete(responseHandler);
160:             }).collect(Collectors.toList());
161: 
162:             pendingFetchRequestFuture.complete(null);
163:             return new PollResult(requests);
164:         } catch (Throwable t) {
165:             // A "dummy" poll result is returned here rather than rethrowing the error because any error
166:             // that is thrown from any RequestManager.poll() method interrupts the polling of the other
167:             // request managers.
168:             pendingFetchRequestFuture.completeExceptionally(t);
169:             return PollResult.EMPTY;
170:         } finally {
171:             pendingFetchRequestFuture = null;
172:         }
173:     }
174: 
175:     /**
176:      * Simple functional interface to all passing in a method reference for improved readability.
177:      */
178:     @FunctionalInterface
179:     protected interface FetchRequestPreparer {
180: 
181:         Map<Node, FetchSessionHandler.FetchRequestData> prepare();
182:     }
183: }
